import { createClient } from '@/lib/supabase/server';
import { notFound } from 'next/navigation';
import { Calendar, ArrowLeft, Tag } from 'lucide-react';
import Link from 'next/link';

export async function generateMetadata({ params }: { params: { slug: string } }) {
  const supabase = await createClient();
  const { data } = await supabase
    .from('journals')
    .select('title, content')
    .eq('slug', params.slug)
    .single();

  if (!data) return { title: 'Not Found' };

  return {
    title: `${data.title} | Advaitha Yogam`,
    description: data.content?.substring(0, 160) || 'Spiritual journal entry',
  };
}

export default async function JournalEntryPage({ params }: { params: { slug: string } }) {
  const supabase = await createClient();
  
  const { data: journal, error } = await supabase
    .from('journals')
    .select('*')
    .eq('slug', params.slug)
    .single();

  if (error || !journal) {
    notFound();
  }

  return (
    <div className="min-h-screen bg-[#FAFAFA] py-12 px-4 sm:px-6 lg:px-8 font-[family-name:var(--font-outfit)]">
      <div className="max-w-3xl mx-auto">
        <Link href="/journals" className="inline-flex items-center gap-2 text-sm font-medium text-gray-500 hover:text-[#2D5A3D] transition-colors mb-8">
          <ArrowLeft size={16} /> Back to Journals
        </Link>
        
        <article className="bg-white rounded-2xl overflow-hidden shadow-sm border border-gray-100">
          {journal.image_url && (
            <div className="w-full aspect-[21/9] overflow-hidden">
              <img 
                src={journal.image_url} 
                alt={journal.title} 
                className="w-full h-full object-cover"
              />
            </div>
          )}
          
          <div className="p-8 md:p-12">
            <div className="flex flex-wrap gap-2 mb-6">
              {journal.tags?.map((tag: string) => (
                <span key={tag} className="inline-flex items-center gap-1.5 text-xs font-semibold tracking-wider uppercase text-amber-600 bg-amber-50 px-3 py-1.5 rounded-full">
                  <Tag size={12} /> {tag}
                </span>
              ))}
            </div>
            
            <h1 className="text-4xl md:text-5xl font-bold font-[family-name:var(--font-cormorant)] text-gray-900 mb-6 leading-tight">
              {journal.title}
            </h1>
            
            <div className="flex items-center gap-2 text-sm text-gray-500 mb-10 pb-10 border-b border-gray-100">
              <Calendar size={16} />
              <span>
                Published on {journal.published_at 
                  ? new Date(journal.published_at).toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' })
                  : new Date(journal.created_at).toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' })
                }
              </span>
            </div>
            
            <div className="prose prose-lg prose-emerald max-w-none font-[family-name:var(--font-cormorant)] text-gray-800 leading-relaxed">
              {journal.content?.split('\n').map((paragraph: string, idx: number) => (
                paragraph.trim() ? <p key={idx} className="mb-6">{paragraph}</p> : <br key={idx} />
              ))}
            </div>
          </div>
        </article>
      </div>
    </div>
  );
}
